            // Calculate the number of ways to choose 2 points from each row
            const ways1 = (count1 * (count1 - 1)) / 2;
            const ways2 = (count2 * (count2 - 1)) / 2;

            // Add the product of the ways to the result
            result = (result + ways1 * ways2) % MOD;
        }
    }

    return result;
}

